import{c as a,Q as n,j as t,m as e}from"./chunks/framework.CBiVa4O3.js";const d=JSON.parse('{"title":"红蓝紫队:攻防演练 / 检测覆盖 / Purple Team 思维","description":"","frontmatter":{},"headers":[],"relativePath":"../securityLearning/24-红蓝紫队.md","filePath":"../securityLearning/24-红蓝紫队.md","lastUpdated":1778496697000}'),p={name:"../securityLearning/24-红蓝紫队.md"};function o(l,s,i,r,c,u){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="红蓝紫队-攻防演练-检测覆盖-purple-team-思维" tabindex="-1">红蓝紫队:攻防演练 / 检测覆盖 / Purple Team 思维 <a class="header-anchor" href="#红蓝紫队-攻防演练-检测覆盖-purple-team-思维" aria-label="Permalink to &quot;红蓝紫队:攻防演练 / 检测覆盖 / Purple Team 思维&quot;">​</a></h1><p>读到这一篇,前面 21-23 已经把&quot;攻击者拿到入口之后干什么&quot;这条线讲完——侦察、Web 入口、内网横移。但所有那些都是<strong>一个人</strong>在打。真实世界里,公司不会雇个渗透测试员打三天就完事——<strong>真正在跟攻击者赛跑的,是一支建制化的&quot;红队 + 蓝队&quot;团队</strong>,以及它们之间的协作模式「紫队(Purple Team)」。新手最容易误解的两件事:<strong>第一,紫队不是中间色,不是&quot;颜色调和&quot;</strong>,是红蓝坐在一起干活的工作方式;<strong>第二,红队不是渗透测试</strong>,虽然技术栈重叠,但目标、时间尺度、对手都完全不同。这一篇讲清楚这三个角色怎么分工、怎么协同、产物是什么,以及一家<strong>没有钱养专职红蓝队的小公司</strong>怎么从零搭建一个能跑起来的&quot;轻量紫队&quot;。</p><blockquote><p>一句话先记住:<strong>红队问&quot;我能不能进得来&quot;、蓝队问&quot;我能不能看见你进来&quot;、紫队问&quot;我能不能下次就看见你进来&quot;</strong>。三个问题对应三个产物——红队产攻击路径,蓝队产检测规则,紫队产**&quot;攻击路径 ↔ 检测规则&quot;的映射表**。这张映射表挂在 MITRE ATT&amp;CK 矩阵上,就是现代安全运营的核心 KPI:<strong>检测覆盖率(detection coverage)</strong>。一家公司安全水平怎么样,不看它买了多少安全产品,<strong>看它能在 ATT&amp;CK 矩阵的多少格子里说&quot;这条我能告警&quot;</strong>。</p></blockquote><hr><h2 id="一、为什么需要-两支队伍" tabindex="-1">一、为什么需要&quot;两支队伍&quot; <a class="header-anchor" href="#一、为什么需要-两支队伍" aria-label="Permalink to &quot;一、为什么需要&quot;两支队伍&quot;&quot;">​</a></h2><h3 id="_1-1-一个不对称的赛局" tabindex="-1">1.1 一个不对称的赛局 <a class="header-anchor" href="#_1-1-一个不对称的赛局" aria-label="Permalink to &quot;1.1 一个不对称的赛局&quot;">​</a></h3><p>防御方天然处于劣势,原因是「不对称」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>攻击者:只要找到一个洞 → 进来</span></span>
<span class="line"><span>防御者:必须堵上所有洞 → 守住</span></span>
<span class="line"><span></span></span>
<span class="line"><span>攻击者:时间无限,可以盯一年</span></span>
<span class="line"><span>防御者:每周都有 deadline,人手有限</span></span>
<span class="line"><span></span></span>
<span class="line"><span>攻击者:用一套工具打一百家</span></span>
<span class="line"><span>防御者:每家都要自己研究怎么防</span></span>
<span class="line"><span></span></span>
<span class="line"><span>攻击者:失败没成本,换一台机器再来</span></span>
<span class="line"><span>防御者:失败一次就上新闻</span></span></code></pre></div><p><strong>这个不对称解释了为什么&quot;事后被打&quot;是常态</strong>——不是工程师菜,是结构性的。能补救的不是&quot;再加 50% 防御&quot;,<strong>而是&quot;提前模拟攻击,验证自己的防御能不能看见&quot;</strong>。这就是红蓝队存在的根本理由——用一群&quot;自己人&quot;扮演攻击者,<strong>逼着防御方在被真攻击者打之前就先疼一次</strong>。</p><h3 id="_1-2-三种-我打我自己-的活动-别搞混" tabindex="-1">1.2 三种&quot;我打我自己&quot;的活动,别搞混 <a class="header-anchor" href="#_1-2-三种-我打我自己-的活动-别搞混" aria-label="Permalink to &quot;1.2 三种&quot;我打我自己&quot;的活动,别搞混&quot;">​</a></h3><table tabindex="0"><thead><tr><th>活动</th><th>目的</th><th>时间尺度</th><th>防御方知不知道</th></tr></thead><tbody><tr><td><strong>漏洞扫描</strong></td><td>找已知 CVE</td><td>分钟级</td><td>知道</td></tr><tr><td><strong>渗透测试(pentest)</strong></td><td>有授权打一个范围</td><td>1-2 周</td><td>知道,且配合</td></tr><tr><td><strong>红队演练(red team)</strong></td><td>模拟真实 APT 全链路</td><td>1-6 个月</td><td><strong>不知道</strong>(或只有少数人知)</td></tr><tr><td><strong>桌面演练(tabletop)</strong></td><td>纸面上对剧本</td><td>几小时</td><td>知道,围坐讨论</td></tr><tr><td><strong>紫队(purple team)</strong></td><td>红蓝同步干活</td><td>几天到几周</td><td>知道,<strong>实时联调</strong></td></tr></tbody></table><blockquote><p><strong>关键差别</strong>:扫描和 pentest 的产物是「漏洞清单」,红队的产物是「<strong>完整的攻击链路 + 检测盲区</strong>」,紫队的产物是「<strong>每条链路对应的检测规则</strong>」。给老板看的不是&quot;我们扫到 200 个漏洞&quot;,<strong>而是&quot;我们 ATT&amp;CK 覆盖率从 30% 提到 60%&quot;</strong>。</p></blockquote><hr><h2 id="二、红队-模拟真实攻击者" tabindex="-1">二、红队:模拟真实攻击者 <a class="header-anchor" href="#二、红队-模拟真实攻击者" aria-label="Permalink to &quot;二、红队:模拟真实攻击者&quot;">​</a></h2><h3 id="_2-1-红队的定义" tabindex="-1">2.1 红队的定义 <a class="header-anchor" href="#_2-1-红队的定义" aria-label="Permalink to &quot;2.1 红队的定义&quot;">​</a></h3><p>红队不是&quot;高级渗透测试员&quot;。<strong>它是一个被授权扮演真实威胁演员(threat actor)的内部团队</strong>,目标不是&quot;找洞&quot;,而是&quot;<strong>走完一次完整的攻击链路</strong>,看蓝队能不能发现&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>渗透测试目标:</span></span>
<span class="line"><span>   &quot;请测一下这个 Web 应用的安全性&quot;</span></span>
<span class="line"><span>   → 拿到入口就算赢</span></span>
<span class="line"><span></span></span>
<span class="line"><span>红队目标:</span></span>
<span class="line"><span>   &quot;假装你是 APT29,目标是偷到 CRM 数据库的客户信息&quot;</span></span>
<span class="line"><span>   → 钓鱼 → 上线 → 提权 → 横移 → 访问 CRM → 落地</span></span>
<span class="line"><span>   → 全程不被发现 = 真赢</span></span></code></pre></div><blockquote><p>渗透测试是「<strong>点</strong>」,红队是「<strong>链</strong>」。链上任何一环被蓝队抓住,红队就失败了——所以红队天然要把&quot;<strong>怎么不被发现</strong>&quot;放在和&quot;<strong>怎么打进去</strong>&quot;同等重要的位置。</p></blockquote><h3 id="_2-2-ttp-战术-技术-流程" tabindex="-1">2.2 TTP:战术 / 技术 / 流程 <a class="header-anchor" href="#_2-2-ttp-战术-技术-流程" aria-label="Permalink to &quot;2.2 TTP:战术 / 技术 / 流程&quot;">​</a></h3><p>红队的&quot;剧本&quot;用 <strong>TTP(Tactics / Techniques / Procedures)</strong> 描述,这是 MITRE ATT&amp;CK 的核心词汇:</p><ul><li><strong>Tactic(战术)</strong>:攻击者<strong>要达到什么目标</strong>——初始访问、持久化、横向移动、数据窃取。这是 ATT&amp;CK 矩阵的<strong>列</strong>。</li><li><strong>Technique(技术)</strong>:<strong>用什么手段</strong>达到——钓鱼、漏洞利用、Pass-the-Hash。这是 ATT&amp;CK 矩阵的<strong>格子</strong>。</li><li><strong>Procedure(流程)</strong>:<strong>具体怎么做</strong>——&quot;用 Cobalt Strike 的 PSExec 模块,跳板机是 X,凭据来自 mimikatz&quot;。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tactic:        Initial Access</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Technique:     Phishing (T1566)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Sub-technique: Spearphishing Attachment (T1566.001)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>Procedure:     APT29 用 .docm 文件夹带 base64 编码的 PowerShell loader</span></span></code></pre></div><p><strong>为什么这套抽象重要</strong>:它让&quot;防御 vs 攻击&quot;有了共同语言。蓝队不用关心&quot;这次具体是哪个 APT 组织&quot;,<strong>它只需要知道&quot;我能不能检测到 T1566.001 这个技术&quot;</strong>——一条检测规则对应一个 Technique ID,<strong>一千个 APT 都打不穿同一个检测</strong>。</p><h3 id="_2-3-红队和真-apt-的差距" tabindex="-1">2.3 红队和真 APT 的差距 <a class="header-anchor" href="#_2-3-红队和真-apt-的差距" aria-label="Permalink to &quot;2.3 红队和真 APT 的差距&quot;">​</a></h3><p>红队再像也是&quot;扮演&quot;,有几个真实攻击者没有的约束:</p><ul><li><strong>道德边界</strong>:不破坏生产、不真正泄露数据、不打员工家庭</li><li><strong>时间预算</strong>:再长也就 3-6 个月,APT 可以盯三年</li><li><strong>资源</strong>:不会真的烧 0day——一个 0day 黑市百万美金,内部红队不舍得用</li><li><strong>退出条款</strong>:打到某个里程碑就停,真攻击者会继续扎根</li></ul><p>所以红队的<strong>真实价值不是&quot;完美模拟&quot;,而是&quot;覆盖 90% 的常见 TTP</strong>——APT29、Lazarus、勒索家族这些公开的剧本演一遍,<strong>绝大多数蓝队的盲区都会暴露</strong>。</p><hr><h2 id="三、蓝队-检测-响应-取证-加固" tabindex="-1">三、蓝队:检测 / 响应 / 取证 / 加固 <a class="header-anchor" href="#三、蓝队-检测-响应-取证-加固" aria-label="Permalink to &quot;三、蓝队:检测 / 响应 / 取证 / 加固&quot;">​</a></h2><h3 id="_3-1-蓝队的四大职能" tabindex="-1">3.1 蓝队的四大职能 <a class="header-anchor" href="#_3-1-蓝队的四大职能" aria-label="Permalink to &quot;3.1 蓝队的四大职能&quot;">​</a></h3><p>蓝队不是&quot;安全运维&quot;。它做四件事,<strong>任何一件做不好,前面三件都白费</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 检测(Detection)</span></span>
<span class="line"><span>   写日志 / 写告警规则 / 看 SIEM</span></span>
<span class="line"><span>   → &quot;有人在 PowerShell 里调 mimikatz&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 响应(Response)</span></span>
<span class="line"><span>   接到告警 → 判定 → 处置 → 隔离</span></span>
<span class="line"><span>   → SLA:5 分钟看到、15 分钟决定、1 小时隔离</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 取证(Forensics)</span></span>
<span class="line"><span>   事后还原:谁进来的、什么时候、动了什么、走了什么</span></span>
<span class="line"><span>   → 内存 dump、磁盘镜像、日志关联</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 加固(Hardening)</span></span>
<span class="line"><span>   把这次的教训写进基线、固化到 IaC</span></span>
<span class="line"><span>   → 下次同类攻击直接打不出第一步</span></span></code></pre></div><p><strong>新手最大的误区是只看「检测」</strong>——以为蓝队就是写 Sigma 规则。<strong>实际上检测只是把球抢到,响应不快、取证不严、加固不落,等于白抢</strong>。一个真实数字:Mandiant 报告 2024 年企业平均<strong>驻留时间(dwell time)是 10 天</strong>——攻击者进来到被发现,平均要 10 天。<strong>前 9 天蓝队都不知情</strong>,这才是常态。</p><h3 id="_3-2-检测金字塔-detection-pyramid" tabindex="-1">3.2 检测金字塔(Detection Pyramid) <a class="header-anchor" href="#_3-2-检测金字塔-detection-pyramid" aria-label="Permalink to &quot;3.2 检测金字塔(Detection Pyramid)&quot;">​</a></h3><p>蓝队的检测能力分层,<strong>越往上越值钱、越难替换</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  ┌──────────┐</span></span>
<span class="line"><span>                  │   TTPs   │   ← 最值钱(描述&quot;行为模式&quot;)</span></span>
<span class="line"><span>                  └──────────┘</span></span>
<span class="line"><span>                ┌──────────────┐</span></span>
<span class="line"><span>                │   Tools      │   ← 检测攻击工具的特征</span></span>
<span class="line"><span>                └──────────────┘</span></span>
<span class="line"><span>              ┌──────────────────┐</span></span>
<span class="line"><span>              │ Network Artifacts │  ← URL / UA / 流量特征</span></span>
<span class="line"><span>              └──────────────────┘</span></span>
<span class="line"><span>            ┌──────────────────────┐</span></span>
<span class="line"><span>            │   Host Artifacts     │  ← 文件名 / 注册表 key</span></span>
<span class="line"><span>            └──────────────────────┘</span></span>
<span class="line"><span>          ┌──────────────────────────┐</span></span>
<span class="line"><span>          │      Domain Names        │  ← 攻击者域名</span></span>
<span class="line"><span>          └──────────────────────────┘</span></span>
<span class="line"><span>        ┌──────────────────────────────┐</span></span>
<span class="line"><span>        │       IP Addresses           │  ← 黑 IP</span></span>
<span class="line"><span>        └──────────────────────────────┘</span></span>
<span class="line"><span>      ┌──────────────────────────────────┐</span></span>
<span class="line"><span>      │       Hash Values                │  ← 文件 hash(最廉价)</span></span>
<span class="line"><span>      └──────────────────────────────────┘</span></span></code></pre></div><p>这叫 <strong>Pyramid of Pain</strong>(David Bianco 提出)——<strong>越往上,攻击者绕过的代价越高</strong>。</p><ul><li>你封了一个 hash,攻击者改一个字节就绕过——<strong>他疼 1 秒</strong></li><li>你封了一个 IP,他换一台 VPS——<strong>疼 5 分钟</strong></li><li>你检测到了某个 RAT 工具的 C2 协议特征——<strong>他要重写工具,疼几周</strong></li><li>你检测到了&quot;任意 PowerShell 从内存里调 mimikatz 然后访问域控&quot;这种<strong>行为模式</strong>——<strong>他要换整套打法,疼几个月</strong></li></ul><blockquote><p><strong>写检测规则的核心心法:往金字塔顶端写</strong>。基于 hash / IP 的规则是廉价票,基于 TTP 的规则才是护城河。这也是为什么 ATT&amp;CK 矩阵成了&quot;行业通用语言&quot;——它就是 TTP 的目录。</p></blockquote><h3 id="_3-3-detection-engineering-不是写正则-是写代码" tabindex="-1">3.3 Detection Engineering:不是写正则,是写代码 <a class="header-anchor" href="#_3-3-detection-engineering-不是写正则-是写代码" aria-label="Permalink to &quot;3.3 Detection Engineering:不是写正则,是写代码&quot;">​</a></h3><p>现代蓝队把&quot;写检测规则&quot;工程化,叫 <strong>Detection Engineering</strong>,完整流程:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 选定一个 ATT&amp;CK Technique(e.g. T1003.001 LSASS 内存读取)</span></span>
<span class="line"><span>2. 调研:攻击者会怎么具体执行?有什么变种?</span></span>
<span class="line"><span>3. 写规则(Sigma / Splunk SPL / Elastic EQL)</span></span>
<span class="line"><span>4. 红队实际跑一遍 → 触发了没?</span></span>
<span class="line"><span>5. 测假阳性:正常业务会不会触发?</span></span>
<span class="line"><span>6. 编写 Runbook:告警来了运营怎么处置?</span></span>
<span class="line"><span>7. 进版本控制(detection-as-code)</span></span>
<span class="line"><span>8. CI 测试:每次规则改动跑回归</span></span>
<span class="line"><span>9. 上线 → 监控指标 → 回到 1</span></span></code></pre></div><blockquote><p>检测规则现在和后端代码一样进 Git、走 PR、跑 CI——这就是&quot;detection-as-code&quot;。<strong>写一条好规则的工作量,等同于写一个微服务</strong>。Google、Microsoft 都有专职的 detection engineer 岗位,薪资和 SRE 一个档次。</p></blockquote><hr><h2 id="四、紫队-不是颜色-是工作方式" tabindex="-1">四、紫队:不是颜色,是工作方式 <a class="header-anchor" href="#四、紫队-不是颜色-是工作方式" aria-label="Permalink to &quot;四、紫队:不是颜色,是工作方式&quot;">​</a></h2><h3 id="_4-1-紫队的-反直觉-定义" tabindex="-1">4.1 紫队的&quot;反直觉&quot;定义 <a class="header-anchor" href="#_4-1-紫队的-反直觉-定义" aria-label="Permalink to &quot;4.1 紫队的&quot;反直觉&quot;定义&quot;">​</a></h3><p>新手一听紫队,第一反应:「啊,介于红和蓝之间的中等水平」。<strong>完全错</strong>。紫队不是一支队伍,<strong>是红蓝两支队伍坐在同一个屋里实时联调的工作方式</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统模式(红蓝分离):</span></span>
<span class="line"><span>   红队 ──── 打两周 ────→ 报告</span></span>
<span class="line"><span>                                ↓</span></span>
<span class="line"><span>   蓝队 ←──── 拿到报告 ─── 看一周 → 改规则</span></span>
<span class="line"><span>                                ↓ 几周后</span></span>
<span class="line"><span>   红队 ──── 再打一次 ────→ 再报告</span></span>
<span class="line"><span>   ↑ 反馈周期 = 月级</span></span>
<span class="line"><span></span></span>
<span class="line"><span>紫队模式(同步工作):</span></span>
<span class="line"><span>   红队 「我现在跑 mimikatz」</span></span>
<span class="line"><span>   蓝队 「我没看到告警」</span></span>
<span class="line"><span>   红队 「我换 base64 编码再试」</span></span>
<span class="line"><span>   蓝队 「现在 SIEM 触发了一条,但 5 分钟才到」</span></span>
<span class="line"><span>   红队 → 蓝队 → 红队</span></span>
<span class="line"><span>   ↑ 反馈周期 = 分钟级</span></span></code></pre></div><p><strong>核心价值:把&quot;打 → 报告 → 改&quot;的几周缩到几小时</strong>。一周紫队演练能产出的检测规则,等于半年传统模式。</p><h3 id="_4-2-紫队的几种节奏" tabindex="-1">4.2 紫队的几种节奏 <a class="header-anchor" href="#_4-2-紫队的几种节奏" aria-label="Permalink to &quot;4.2 紫队的几种节奏&quot;">​</a></h3><ul><li><strong>Continuous Purple</strong>(持续紫队):每周固定一天,红蓝同坐,挑一个 Technique 联调。Google、Microsoft 在用。</li><li><strong>Sprint Purple</strong>(冲刺紫队):每季度集中一周,围绕一个主题(如&quot;勒索软件链路&quot;)全员联调。多数中型公司在用。</li><li><strong>Adversary Emulation</strong>(对抗模拟):选定一个真实 APT 剧本(如 APT29 的 SolarWinds 攻击链),按 ATT&amp;CK 报告里的每个 step 实际复现 → 检查每步的检测覆盖。</li></ul><blockquote><p><strong>紫队是文化,不是组织架构</strong>。一家公司可能没有&quot;紫队部门&quot;,但红蓝两个团队每周开一次同步会、用同一个 ATT&amp;CK 仪表盘——它就是紫队成熟体。</p></blockquote><hr><h2 id="五、att-ck-矩阵与红蓝映射" tabindex="-1">五、ATT&amp;CK 矩阵与红蓝映射 <a class="header-anchor" href="#五、att-ck-矩阵与红蓝映射" aria-label="Permalink to &quot;五、ATT&amp;CK 矩阵与红蓝映射&quot;">​</a></h2><p>ATT&amp;CK 是 MITRE 维护的攻击者行为知识库,<strong>14 个战术、~200 个技术、~500 个子技术</strong>。它的物理形态是一张矩阵,<strong>列是战术(攻击的&quot;阶段&quot;)、格子是技术(具体手段)</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ATT&amp;CK Enterprise Matrix(简化,实际更宽)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>│ Reconnaissance │ Initial Access │ Execution    │ Persistence  │ Priv Esc     │ Defense Eva │ Cred Access │ Discovery   │ Lateral Mov │ C&amp;C        │ Exfil       │ Impact     │</span></span>
<span class="line"><span>├────────────────┼────────────────┼──────────────┼──────────────┼──────────────┼─────────────┼─────────────┼─────────────┼─────────────┼────────────┼─────────────┼────────────┤</span></span>
<span class="line"><span>│ Active Scan    │ Phishing       │ PowerShell   │ Scheduled Tk │ Token Manip  │ Obfuscation │ Brute Force │ Account Disc│ RDP         │ HTTPS      │ Exfil over │ Encrypt    │</span></span>
<span class="line"><span>│ Search Open DB │ Drive-by       │ WMI          │ Registry Run │ Bypass UAC   │ Process Inj │ Credential  │ Network Sc  │ SMB/Windows │ DNS Tun    │  C2         │  for       │</span></span>
<span class="line"><span>│ Phishing for I │ Exploit Pub-Fac│ Cmd &amp; Script │ DLL Search O │ Sudo &amp; Sudo  │ Indicator R │  Dumping    │ File &amp; Dir  │ Pass-the-Ha │ Web Service│ Exfil to    │  Impact    │</span></span>
<span class="line"><span>│ Search Victim  │ Hardware Add   │ Container    │ Boot/Logon   │ Process Inj  │ Disable Sec │ Steal Web S │ Permission  │ Internal Sp │ Encrypted  │  Cloud      │ Service S  │</span></span>
<span class="line"><span>│ ...            │ Supply Chain   │ Native API   │ Account Mani │ ...          │ Masquerade  │ Kerberoast  │ System Info │ Taint Share │  Channel   │ Schedule    │ Defacement │</span></span>
<span class="line"><span>│                │ Valid Account  │ Inter-Pro Co │ Create Acct  │              │ ...         │ ...         │ ...         │ ...         │ ...        │  Transfer   │ ...        │</span></span>
<span class="line"><span>└────────────────┴────────────────┴──────────────┴──────────────┴──────────────┴─────────────┴─────────────┴─────────────┴─────────────┴────────────┴─────────────┴────────────┘</span></span></code></pre></div><p><strong>红蓝两队怎么用这张图</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>红队视角(从左到右画&quot;攻击路径&quot;):</span></span>
<span class="line"><span>   T1566.001 ──→ T1059.001 ──→ T1547.001 ──→ T1003.001 ──→ T1021.002 ──→ T1041</span></span>
<span class="line"><span>   钓鱼附件      PowerShell    Registry Run    LSASS dump    SMB 横移      C2 外传</span></span>
<span class="line"><span>   (Initial)    (Execution)   (Persistence)   (Credential)  (Lateral)     (Exfil)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>蓝队视角(在每个格子上标颜色):</span></span>
<span class="line"><span>   ┌─────────┐</span></span>
<span class="line"><span>   │ T1566.001│  ← 邮件网关 + 沙箱:有检测,绿色</span></span>
<span class="line"><span>   ├─────────┤</span></span>
<span class="line"><span>   │ T1059.001│  ← AMSI + EDR:有检测,绿色</span></span>
<span class="line"><span>   ├─────────┤</span></span>
<span class="line"><span>   │ T1547.001│  ← 没规则,红色 ←──── 这就是盲区!</span></span>
<span class="line"><span>   ├─────────┤</span></span>
<span class="line"><span>   │ T1003.001│  ← EDR 告警 mimikatz:绿色</span></span>
<span class="line"><span>   ├─────────┤</span></span>
<span class="line"><span>   │ T1021.002│  ← 没规则,红色 ←──── 这也是盲区!</span></span>
<span class="line"><span>   ├─────────┤</span></span>
<span class="line"><span>   │ T1041    │  ← DLP + 流量分析:黄色(有但不全)</span></span>
<span class="line"><span>   └─────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>紫队产物:一张全公司 ATT&amp;CK 覆盖热力图</span></span>
<span class="line"><span>   绿色 = 有检测,红队跑过会触发</span></span>
<span class="line"><span>   黄色 = 有检测,但有漏报或延迟</span></span>
<span class="line"><span>   红色 = 完全没检测,是盲区</span></span></code></pre></div><blockquote><p><strong>这张「热力图」就是现代安全团队最重要的 KPI</strong>——给 CTO / CISO 汇报不讲&quot;我们发了多少告警&quot;,<strong>讲&quot;我们 ATT&amp;CK 覆盖率从 35% 提到 62%&quot;</strong>。MITRE 自己开源了一个工具叫 <strong>ATT&amp;CK Navigator</strong>,就是画这张图用的。</p></blockquote><hr><h2 id="六、攻防演练的完整流程" tabindex="-1">六、攻防演练的完整流程 <a class="header-anchor" href="#六、攻防演练的完整流程" aria-label="Permalink to &quot;六、攻防演练的完整流程&quot;">​</a></h2><p>不管叫红队、紫队还是 tabletop,一次合格的演练分五步:</p><h3 id="_6-1-第一步-目标设定-objective" tabindex="-1">6.1 第一步:目标设定(Objective) <a class="header-anchor" href="#_6-1-第一步-目标设定-objective" aria-label="Permalink to &quot;6.1 第一步:目标设定(Objective)&quot;">​</a></h3><p><strong>最容易跳过、但决定演练价值的一步</strong>。不是&quot;打进来就行&quot;,必须有具体目标:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 差的目标:测试一下我们的安全。</span></span>
<span class="line"><span>✅ 好的目标:</span></span>
<span class="line"><span>   假设攻击者通过钓鱼拿到一个普通员工账号,</span></span>
<span class="line"><span>   72 小时内能不能拿到生产 DB 的客户表?</span></span>
<span class="line"><span>   - 范围:研发网 + 生产 K8s</span></span>
<span class="line"><span>   - 边界:不动 HR 系统、不打员工家庭网络</span></span>
<span class="line"><span>   - 成功标准:能查询到某条客户记录的 SQL 截图</span></span>
<span class="line"><span>   - 蓝队是否知情:不知情(只 CISO 知道)</span></span></code></pre></div><h3 id="_6-2-第二步-攻击执行-execution" tabindex="-1">6.2 第二步:攻击执行(Execution) <a class="header-anchor" href="#_6-2-第二步-攻击执行-execution" aria-label="Permalink to &quot;6.2 第二步:攻击执行(Execution)&quot;">​</a></h3><p>红队按 TTP 剧本展开,<strong>每一步都打两个日志</strong>——一份给自己(取证)、一份给紫队的协调员。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[D+0 10:00] T1566.001 钓鱼,3 人中招</span></span>
<span class="line"><span>[D+0 14:30] T1059.001 PowerShell loader 落地</span></span>
<span class="line"><span>[D+1 09:00] T1003.001 mimikatz 读 LSASS</span></span>
<span class="line"><span>[D+1 15:00] T1021.002 SMB 横移到第二台</span></span>
<span class="line"><span>[D+2 11:00] T1078 域内合法账户接管</span></span>
<span class="line"><span>[D+3 16:00] T1041 拿到目标 DB 表</span></span></code></pre></div><h3 id="_6-3-第三步-检测评估-detection-assessment" tabindex="-1">6.3 第三步:检测评估(Detection Assessment) <a class="header-anchor" href="#_6-3-第三步-检测评估-detection-assessment" aria-label="Permalink to &quot;6.3 第三步:检测评估(Detection Assessment)&quot;">​</a></h3><p>演练结束后,<strong>对每个攻击步骤问蓝队三个问题</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 触发了告警吗?</span></span>
<span class="line"><span>2. 告警有没有被人看到?(SIEM 一天一万条告警,看不过来就等于没有)</span></span>
<span class="line"><span>3. 看到了有没有正确判断?(误判成&quot;运维操作&quot;就等于没看到)</span></span></code></pre></div><p>三个问题对应<strong>三种失败</strong>:<strong>没检测、没看见、没看懂</strong>。每一种的修复方式完全不同——</p><ul><li>没检测 → 写新规则</li><li>没看见 → 调告警优先级、减噪音</li><li>没看懂 → 写 Runbook、培训分析师</li></ul><h3 id="_6-4-第四步-复盘-after-action-review" tabindex="-1">6.4 第四步:复盘(After-Action Review) <a class="header-anchor" href="#_6-4-第四步-复盘-after-action-review" aria-label="Permalink to &quot;6.4 第四步:复盘(After-Action Review)&quot;">​</a></h3><p>复盘要避免两个反模式:<strong>&quot;批斗大会&quot;</strong>(红队炫技、蓝队挨打)和**&quot;皆大欢喜&quot;**(各说各话、不出产物)。</p><p>正确的复盘开法:<strong>对着 ATT&amp;CK 矩阵逐格走</strong>。每格三个问题——红队是怎么打的、蓝队看到了什么、下一步加什么规则。<strong>复盘的产物是工单,不是 PPT</strong>。</p><h3 id="_6-5-第五步-落地-remediation" tabindex="-1">6.5 第五步:落地(Remediation) <a class="header-anchor" href="#_6-5-第五步-落地-remediation" aria-label="Permalink to &quot;6.5 第五步:落地(Remediation)&quot;">​</a></h3><p>复盘产生的工单分三类,优先级也不同:</p><table tabindex="0"><thead><tr><th>类型</th><th>例子</th><th>优先级</th><th>谁负责</th></tr></thead><tbody><tr><td><strong>检测缺口</strong></td><td>写新 Sigma 规则覆盖 T1547.001</td><td>P0(7 天)</td><td>蓝队</td></tr><tr><td><strong>漏洞修复</strong></td><td>修 LDAP 注入</td><td>P1(30 天)</td><td>业务团队</td></tr><tr><td><strong>架构加固</strong></td><td>把 PowerShell 默认 Constrained Mode</td><td>P2(季度)</td><td>平台团队</td></tr></tbody></table><blockquote><p><strong>演练不出工单 = 演练白做</strong>。一次好的紫队演练,产出 20-50 张工单是正常水平,<strong>90 天后回头看完成率,这是真正的 KPI</strong>。</p></blockquote><hr><h2 id="七、桌面演练-live-exercise-ctf-hack-week" tabindex="-1">七、桌面演练 / Live Exercise / CTF / Hack Week <a class="header-anchor" href="#七、桌面演练-live-exercise-ctf-hack-week" aria-label="Permalink to &quot;七、桌面演练 / Live Exercise / CTF / Hack Week&quot;">​</a></h2><p><strong>不是所有演练都要真打</strong>,公司里实际跑的是一个&quot;演练光谱&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>成本低 ←──────────────────────────────────────────→ 成本高</span></span>
<span class="line"><span>真实低 ←──────────────────────────────────────────→ 真实高</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Tabletop]   [CTF/演习场]   [Purple Drill]   [Red Team]   [Adversary Emu]</span></span>
<span class="line"><span> 纸面对剧本   靶机环境演练    红蓝同步联调      盲打全栈      模拟特定 APT</span></span>
<span class="line"><span> 几小时        1-3 天          1 周              1-6 月       3-12 月</span></span></code></pre></div><h3 id="_7-1-桌面演练-tabletop" tabindex="-1">7.1 桌面演练(Tabletop) <a class="header-anchor" href="#_7-1-桌面演练-tabletop" aria-label="Permalink to &quot;7.1 桌面演练(Tabletop)&quot;">​</a></h3><p><strong>最便宜、最被低估</strong>。<strong>没有任何技术执行</strong>,所有人围桌而坐,主持人念剧本——</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主持人:&quot;周五下午 3 点,SOC 收到一条告警:某个员工账号在凌晨 2 点</span></span>
<span class="line"><span>        从俄罗斯 IP 登录,然后下载了 CRM 全表。你下一步做什么?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>值班分析师:&quot;我先看 VPN 日志确认。&quot;</span></span>
<span class="line"><span>主持人:&quot;VPN 日志显示该账号确实 2 点登录,然后被注销了。&quot;</span></span>
<span class="line"><span>分析师:&quot;我冻结账号,通知本人。&quot;</span></span>
<span class="line"><span>主持人:&quot;通知不到本人。&quot;</span></span>
<span class="line"><span>法务负责人:&quot;现在涉及客户数据,要不要触发 GDPR 72 小时报告?&quot;</span></span>
<span class="line"><span>...</span></span></code></pre></div><p><strong>桌面演练的核心价值不是技术,是流程</strong>——谁该打电话给谁、决策权在谁、72 小时报告由谁起草。<strong>真出事时这些事情没演练过,会一团乱</strong>。NIST 推荐每个组织至少一年一次 tabletop,<strong>这是性价比最高的演练形式</strong>。</p><h3 id="_7-2-live-exercise-ctf" tabindex="-1">7.2 Live Exercise / CTF <a class="header-anchor" href="#_7-2-live-exercise-ctf" aria-label="Permalink to &quot;7.2 Live Exercise / CTF&quot;">​</a></h3><p>公司内部办 CTF(Capture the Flag),<strong>给蓝队练手用的</strong>——搭一个靶机环境,藏几个 flag,让员工去打。Google 的 &quot;Caesar&#39;s Wheel&quot;、Meta 的内部 CTF 平台都是这种。</p><p>价值:<strong>让蓝队建立&quot;攻击者直觉&quot;</strong>——你天天写检测规则,自己没真正绕过过 EDR,写的规则就是空谈。</p><h3 id="_7-3-hack-week-红队周" tabindex="-1">7.3 Hack Week / 红队周 <a class="header-anchor" href="#_7-3-hack-week-红队周" aria-label="Permalink to &quot;7.3 Hack Week / 红队周&quot;">​</a></h3><p>公司级活动,<strong>一周时间全公司停手头工作,集中找洞</strong>——Meta 的 &quot;Hacktober&quot;、Microsoft 的 &quot;Blue Hat&quot;、Google 的 &quot;Project Zero&quot; 都是这种文化的延伸。</p><p><strong>核心好处不是找洞数量,是文化建设</strong>——让产品工程师亲身感受&quot;原来我写的代码是这样被打的&quot;,<strong>比安全培训有效一万倍</strong>。</p><hr><h2 id="八、真实公司的红蓝建设" tabindex="-1">八、真实公司的红蓝建设 <a class="header-anchor" href="#八、真实公司的红蓝建设" aria-label="Permalink to &quot;八、真实公司的红蓝建设&quot;">​</a></h2><h3 id="_8-1-google" tabindex="-1">8.1 Google <a class="header-anchor" href="#_8-1-google" aria-label="Permalink to &quot;8.1 Google&quot;">​</a></h3><p>红队对内打、对外做研究(Project Zero),蓝队叫 TAG。关键实践:<strong>Detection-as-code</strong>(规则进 Git、CI 测试)、<strong>BeyondCorp 零信任</strong>(没有&quot;内网&quot;,每个请求独立鉴权,横向移动空间被结构性缩窄)、<strong>持续红队</strong>(全年不间断,不是每年一次)。</p><h3 id="_8-2-meta" tabindex="-1">8.2 Meta <a class="header-anchor" href="#_8-2-meta" aria-label="Permalink to &quot;8.2 Meta&quot;">​</a></h3><p>红队叫 Red Team X。<strong>Hacktober</strong>:每年 10 月全公司参加 CTF,产品工程师必修。<strong>Bug Bounty 与红队联动</strong>:外部赏金报告被内部红队拿来&quot;复现 + 扩展&quot;。内部自研 Adversary Simulation Platform 自动化跑 ATT&amp;CK。</p><h3 id="_8-3-阿里-国内大厂" tabindex="-1">8.3 阿里 / 国内大厂 <a class="header-anchor" href="#_8-3-阿里-国内大厂" aria-label="Permalink to &quot;8.3 阿里 / 国内大厂&quot;">​</a></h3><p>国内特有的是 <strong>HW(护网行动)</strong>——政策驱动的全国大规模红蓝对抗,每年 7-8 月集中两周,所有重点保障单位被外部红队打。好处是&quot;国家级强制&quot;,坏处是<strong>容易变应试</strong>——平时不练、8 月突击。成熟厂(阿里&quot;蓝军&quot;、字节红队、腾讯&quot;湛卢&quot;)在 HW 之外都有常态化红蓝队。</p><blockquote><p>国内外共同点:<strong>一线大厂都把红蓝建设当常态化、工程化的事</strong>,不是&quot;出事找乙方&quot;。</p></blockquote><hr><h2 id="九、小公司从零搭建紫队的最小路径" tabindex="-1">九、小公司从零搭建紫队的最小路径 <a class="header-anchor" href="#九、小公司从零搭建紫队的最小路径" aria-label="Permalink to &quot;九、小公司从零搭建紫队的最小路径&quot;">​</a></h2><p>不是每家公司都能养 50 人的安全部。一家 50-200 人规模的公司,<strong>只有 1-3 个安全工程师</strong>,怎么搭一个能跑起来的&quot;紫队&quot;?以下是<strong>实战可落地的最小路径</strong>:</p><h3 id="_9-1-阶段-0-先有日志-week-0-前置条件" tabindex="-1">9.1 阶段 0:先有日志(Week 0,前置条件) <a class="header-anchor" href="#_9-1-阶段-0-先有日志-week-0-前置条件" aria-label="Permalink to &quot;9.1 阶段 0:先有日志(Week 0,前置条件)&quot;">​</a></h3><p><strong>没有日志就不要谈红蓝队</strong>。先把这五类日志接进 SIEM 或者哪怕一个 ES:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 终端:Sysmon(Windows)/ auditd(Linux)/ macOS Unified Log</span></span>
<span class="line"><span>2. 网络:DNS 查询、HTTP/HTTPS 元数据(Zeek 或 ALB 日志)</span></span>
<span class="line"><span>3. 身份:SSO 登录日志(Okta / 飞书 / 钉钉)</span></span>
<span class="line"><span>4. 云:CloudTrail / 阿里云 ActionTrail / GCP Audit Log</span></span>
<span class="line"><span>5. 关键应用:数据库审计、生产 SSH 跳板机</span></span></code></pre></div><blockquote><p>没日志写规则就是空中楼阁。先花两周把日志管道铺好,<strong>这一步占整个紫队建设 50% 的工作量</strong>。</p></blockquote><h3 id="_9-2-阶段-1-挑十个-technique-week-1-2" tabindex="-1">9.2 阶段 1:挑十个 Technique(Week 1-2) <a class="header-anchor" href="#_9-2-阶段-1-挑十个-technique-week-1-2" aria-label="Permalink to &quot;9.2 阶段 1:挑十个 Technique(Week 1-2)&quot;">​</a></h3><p>不要妄想全覆盖 ATT&amp;CK 的 200 个 Technique。<strong>挑十个</strong>,从勒索软件最常用的开始:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T1566   钓鱼</span></span>
<span class="line"><span>T1059   命令脚本解释器</span></span>
<span class="line"><span>T1003   凭据 dumping</span></span>
<span class="line"><span>T1078   合法账户滥用</span></span>
<span class="line"><span>T1021   远程服务(RDP/SMB)</span></span>
<span class="line"><span>T1486   数据加密勒索</span></span>
<span class="line"><span>T1567   通过 Web 服务外传</span></span>
<span class="line"><span>T1190   公开应用利用</span></span>
<span class="line"><span>T1110   暴力破解</span></span>
<span class="line"><span>T1098   账户操作</span></span></code></pre></div><blockquote><p>这十个覆盖了 80% 的真实事件。能把这十个全部&quot;绿色化&quot;,就比 90% 的公司强了。</p></blockquote><h3 id="_9-3-阶段-2-写检测规则-week-3-6" tabindex="-1">9.3 阶段 2:写检测规则(Week 3-6) <a class="header-anchor" href="#_9-3-阶段-2-写检测规则-week-3-6" aria-label="Permalink to &quot;9.3 阶段 2:写检测规则(Week 3-6)&quot;">​</a></h3><p>每个 Technique 写至少一条 Sigma 规则,<strong>直接抄开源仓库</strong>:</p><ul><li><a href="https://github.com/SigmaHQ/sigma" target="_blank" rel="noreferrer">SigmaHQ/sigma</a> - 几千条社区规则</li><li><a href="https://github.com/elastic/detection-rules" target="_blank" rel="noreferrer">Elastic detection-rules</a></li><li><a href="https://github.com/splunk/security_content" target="_blank" rel="noreferrer">Splunk security_content</a></li></ul><blockquote><p><strong>不要自己从零写</strong>。先抄,跑起来,有假阳性再裁剪。</p></blockquote><h3 id="_9-4-阶段-3-每月一次-micro-drill-月度循环" tabindex="-1">9.4 阶段 3:每月一次 micro-drill(月度循环) <a class="header-anchor" href="#_9-4-阶段-3-每月一次-micro-drill-月度循环" aria-label="Permalink to &quot;9.4 阶段 3:每月一次 micro-drill(月度循环)&quot;">​</a></h3><p>一个人扮红队,<strong>用 <a href="https://github.com/redcanaryco/atomic-red-team" target="_blank" rel="noreferrer">Atomic Red Team</a> 的脚本跑一个 Technique</strong>——这是开源的红队工具,每个 Technique 对应一条 Atomic test,<strong>一条命令就能跑</strong>。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例:模拟 T1003.001 LSASS dump</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Invoke-AtomicTest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> T1003.001</span></span></code></pre></div><p>跑完一小时后,<strong>另一个人扮蓝队</strong>,去 SIEM 里找告警——找到了打绿、没找到打红、半小时才到的打黄。</p><p><strong>一个月跑一个 Technique,一年覆盖 10 个</strong>。这就是最小化的紫队循环。</p><h3 id="_9-4-阶段-4-产物固化-quarter-末" tabindex="-1">9.4 阶段 4:产物固化(Quarter 末) <a class="header-anchor" href="#_9-4-阶段-4-产物固化-quarter-末" aria-label="Permalink to &quot;9.4 阶段 4:产物固化(Quarter 末)&quot;">​</a></h3><p>每个季度把循环产物固化:<strong>检测规则</strong>进 Git 加版本;<strong>Runbook</strong> 写到 wiki;<strong>ATT&amp;CK 覆盖图</strong>更新到 Navigator;<strong>工单</strong>进 Jira、跟踪关闭率。</p><blockquote><p><strong>小公司紫队最大的失败模式不是&quot;做不到&quot;,是&quot;做了忘了&quot;</strong>——演练一次,工单堆在那里,半年后再演练发现盲区还在。<strong>只要工单流转起来,即使是 1 个人的紫队,半年后也能拉开和&quot;啥都不做&quot;的同行 5 个身位</strong>。</p></blockquote><h3 id="_9-5-工具清单-全开源" tabindex="-1">9.5 工具清单(全开源) <a class="header-anchor" href="#_9-5-工具清单-全开源" aria-label="Permalink to &quot;9.5 工具清单(全开源)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日志收集: Wazuh / Elastic Beats / Fluent Bit</span></span>
<span class="line"><span>SIEM:    Wazuh / OpenSearch / Splunk Free</span></span>
<span class="line"><span>EDR:     osquery / Velociraptor / Wazuh</span></span>
<span class="line"><span>攻击模拟: Atomic Red Team / Caldera / Stratus Red Team</span></span>
<span class="line"><span>规则库:   Sigma / Elastic Rules / Splunk ESCU</span></span>
<span class="line"><span>可视化:   MITRE ATT&amp;CK Navigator</span></span>
<span class="line"><span>威胁情报: MISP / OpenCTI</span></span></code></pre></div><p><strong>全部加起来 0 元</strong>。差的不是工具,是<strong>坚持每月跑一次的纪律</strong>。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>红队 = 渗透测试</strong>——错。渗透是点,红队是链,目标和时间尺度完全不同</li><li><strong>紫队是&quot;中等水平的队&quot;</strong>——错。紫队是红蓝同步工作的方式,不是组织</li><li><strong>检测规则越多越好</strong>——错。一条假阳性高的规则比没规则还糟,会让分析师麻木</li><li><strong>买了 EDR 就有了蓝队</strong>——错。EDR 是数据源,没有人写规则、看告警、做响应,等于买了个昂贵的电子记录仪</li><li><strong>演练不演练取证</strong>——错。能检测但还原不出来&quot;攻击者动了什么&quot;,对外通报时一句话都说不出</li><li><strong>演练只测技术、不测流程</strong>——错。72 小时报告、对客户通知、法务介入,这些&quot;流程钟&quot;比技术响应更容易掉链子</li><li><strong>拿 ATT&amp;CK 覆盖率当唯一 KPI</strong>——半错。覆盖率只看&quot;有没有规则&quot;,不看&quot;规则准不准&quot;,<strong>还要配合 MTTR(响应时间)和误报率</strong></li><li><strong>以为红队找出来的洞修了就完事</strong>——错。<strong>修洞 + 写检测</strong>是两件事——你不可能修完所有洞,<strong>但你应该能检测到任何洞被打</strong></li><li><strong>小公司觉得&quot;我又没数据,不会被打&quot;</strong>——错。勒索软件不挑大小,<strong>80% 的勒索受害者员工数 &lt; 200</strong></li><li><strong>以为 HW 期间挺过去就行</strong>——错。真攻击者不看日历。<strong>常态化的紫队循环比 HW 突击有用 100 倍</strong></li></ol><hr><p>下一篇:<code>25-CTF入门.md</code>,讲清楚 CTF(Capture the Flag)五大类别——Web / Pwn / Reverse / Crypto / Misc——每类的核心心智、入门资源、必练题型,以及&quot;为什么 CTF 是性价比最高的安全自学方式&quot;——同样的知识,你看十本书可能没看懂,做三道题就懂了;同时讲清楚 CTF 和真实攻防的 gap——CTF 出题人会&quot;留路&quot;,真实场景没人给你留路,<strong>这两种思维都要练</strong>。</p>`,134)])])}const h=a(p,[["render",o]]);export{d as __pageData,h as default};
